// CLX MCP Tool Gateway — Phase 12: Validate Request
// Validates API key and incoming tool call fields

const headers = $('Webhook Trigger').item.json.headers || {};
const apiKey = headers['x-mcp-api-key'] || headers['X-MCP-API-Key'] || '';
const expectedKey = 'CLX-MCP-' + new Date().getFullYear();

// API key authentication check
// For production, set MCP_WEBHOOK_SECRET in n8n environment and reference it here
// Default key format: CLX-MCP-{year} — replace with a strong secret
if (!apiKey) {
  return {
    json: {
      valid: 'false',
      error: 'Missing X-MCP-API-Key header. Include your MCP webhook secret.',
      tool_name: '',
      tool_input: {},
      start_time: Date.now()
    }
  };
}

const body = $('Webhook Trigger').item.json.body || $('Webhook Trigger').item.json;
const startTime = Date.now();

const validTools = [
  'research_lead', 'score_lead', 'generate_outreach', 'send_outreach',
  'process_booking', 'get_pipeline_stats', 'scan_city',
  'get_lead', 'update_lead_status', 'list_leads'
];

const toolName = body.tool_name || '';
const toolInput = body.tool_input || {};

if (!toolName) {
  return {
    json: {
      valid: 'false',
      error: 'Missing tool_name in request body',
      tool_name: '',
      tool_input: {},
      start_time: startTime
    }
  };
}

if (!validTools.includes(toolName)) {
  return {
    json: {
      valid: 'false',
      error: 'Unknown tool: ' + toolName + '. Available tools: ' + validTools.join(', '),
      tool_name: toolName,
      tool_input: toolInput,
      start_time: startTime
    }
  };
}

// Validate required inputs per tool
const requiredInputs = {
  research_lead: ['lead_id', 'company'],
  score_lead: ['lead_id', 'company'],
  generate_outreach: ['lead_id', 'full_name', 'company'],
  send_outreach: ['lead_id', 'email'],
  process_booking: ['lead_id', 'full_name', 'reply_text'],
  get_pipeline_stats: [],
  scan_city: ['city', 'industry'],
  get_lead: [],
  update_lead_status: ['lead_id', 'lead_status'],
  list_leads: []
};

const required = requiredInputs[toolName] || [];
const missing = required.filter(field => !toolInput[field]);

if (missing.length > 0) {
  return {
    json: {
      valid: 'false',
      error: 'Missing required inputs: ' + missing.join(', '),
      tool_name: toolName,
      tool_input: toolInput,
      start_time: startTime
    }
  };
}

return {
  json: {
    valid: 'true',
    tool_name: toolName,
    tool_input: toolInput,
    start_time: startTime
  }
};

// Handle: research_lead
const ctx = $('Validate Request').item.json;
const input = ctx.tool_input;
const now = new Date().toISOString();

// Update lead status to trigger research workflow
return {
  json: {
    tool_name: ctx.tool_name,
    start_time: ctx.start_time,
    lead_id: input.lead_id,
    update_body: {
      company: input.company || '',
      industry: input.industry || '',
      job_title: input.job_title || '',
      city: input.city || '',
      product_type: input.product_type || '',
      lead_status: 'New Lead',
      updated_at: now
    }
  }
};

// Handle: score_lead — set status to Researched to trigger scoring
const ctx = $('Validate Request').item.json;
const input = ctx.tool_input;
return {
  json: {
    tool_name: ctx.tool_name,
    start_time: ctx.start_time,
    lead_id: input.lead_id,
    update_body: { lead_status: 'Researched', updated_at: new Date().toISOString() }
  }
};

// Handle: generate_outreach — set status to Campaign Assigned to trigger outreach gen
const ctx = $('Validate Request').item.json;
const input = ctx.tool_input;
return {
  json: {
    tool_name: ctx.tool_name,
    start_time: ctx.start_time,
    lead_id: input.lead_id,
    update_body: { lead_status: 'Campaign Assigned', recommended_campaign_type: input.campaign_name || 'automation_campaign', updated_at: new Date().toISOString() }
  }
};

// Handle: send_outreach — set status to Outreach Ready to trigger sender
const ctx = $('Validate Request').item.json;
const input = ctx.tool_input;
return {
  json: {
    tool_name: ctx.tool_name,
    start_time: ctx.start_time,
    lead_id: input.lead_id,
    update_body: { lead_status: 'Outreach Ready', updated_at: new Date().toISOString() }
  }
};

// Handle: process_booking — set status to Replied with reply_text to trigger booking
const ctx = $('Validate Request').item.json;
const input = ctx.tool_input;
return {
  json: {
    tool_name: ctx.tool_name,
    start_time: ctx.start_time,
    lead_id: input.lead_id,
    update_body: { lead_status: 'Replied', reply_text: input.reply_text || '', updated_at: new Date().toISOString() }
  }
};

// Handle: get_pipeline_stats — calculate stats from all leads
const ctx = $('Validate Request').item.json;
const allItems = $('Execute Pipeline Stats').all();
const leads = allItems.map(i => i.json);
const total = leads.length;
const counts = {};
for (const lead of leads) {
  const s = lead.lead_status || 'Unknown';
  counts[s] = (counts[s] || 0) + 1;
}
return {
  json: {
    tool_name: ctx.tool_name,
    start_time: ctx.start_time,
    result: { total_leads: total, status_counts: counts }
  }
};

// Handle: scan_city — insert a scan job into leads as a trigger
const ctx = $('Validate Request').item.json;
const input = ctx.tool_input;
return {
  json: {
    tool_name: ctx.tool_name,
    start_time: ctx.start_time,
    result: {
      message: 'City scan queued. The CLX City Scan Discovery workflow will process ' + input.industry + ' in ' + input.city + ' on next scheduled run.',
      city: input.city,
      industry: input.industry,
      product_type: input.product_type || ''
    }
  }
};

// CLX MCP Tool Gateway — Format Response
// Wraps tool handler output in standard MCP response format

try {
  // Find the validate request context from upstream
  let ctx;
  try { ctx = $('Validate Request').item.json; } catch(e) { ctx = { tool_name: 'unknown', start_time: Date.now() }; }

  const toolName = ctx.tool_name;
  const startTime = ctx.start_time || Date.now();
  const executionTime = Date.now() - startTime;

  // Get the result from whichever handler ran
  // The current item json is the output from the last executed node
  const handlerOutput = $input.item.json;

  // If the handler output has a result key use it otherwise use the whole output
  const data = handlerOutput.result || handlerOutput;

  return {
    json: {
      success: true,
      tool: toolName,
      data: data,
      timestamp: new Date().toISOString(),
      execution_time_ms: executionTime
    }
  };
} catch (error) {
  return {
    json: {
      success: false,
      tool: 'unknown',
      error: error.message,
      timestamp: new Date().toISOString(),
      execution_time_ms: 0
    }
  };
}

// Format error response for invalid requests
const ctx = $('Validate Request').item.json;
return {
  json: {
    success: false,
    tool: ctx.tool_name || 'unknown',
    error: ctx.error,
    timestamp: new Date().toISOString(),
    execution_time_ms: Date.now() - (ctx.start_time || Date.now())
  }
};

// CLX MCP Tool Gateway — Tool Registry
// Returns all available tools in MCP-compatible format

return {
  json: {
    tools: [
      {
        name: 'research_lead',
        description: 'Research a company and generate AI business intelligence',
        inputSchema: {
          type: 'object',
          properties: {
            lead_id: { type: 'string', description: 'UUID of the lead in Supabase' },
            company: { type: 'string', description: 'Company name to research' },
            industry: { type: 'string', description: 'Industry category' },
            job_title: { type: 'string', description: 'Contact job title' },
            city: { type: 'string', description: 'City location' },
            product_type: { type: 'string', description: 'Product/service type' }
          },
          required: ['lead_id', 'company']
        }
      },
      {
        name: 'score_lead',
        description: 'Score a lead 0-100 based on business potential',
        inputSchema: {
          type: 'object',
          properties: {
            lead_id: { type: 'string', description: 'UUID of the lead' },
            company: { type: 'string', description: 'Company name' },
            industry: { type: 'string', description: 'Industry category' },
            job_title: { type: 'string', description: 'Contact job title' },
            research_summary: { type: 'string', description: 'Existing research summary' }
          },
          required: ['lead_id', 'company']
        }
      },
      {
        name: 'generate_outreach',
        description: 'Generate personalized outreach messages for a lead',
        inputSchema: {
          type: 'object',
          properties: {
            lead_id: { type: 'string', description: 'UUID of the lead' },
            full_name: { type: 'string', description: 'Contact full name' },
            company: { type: 'string', description: 'Company name' },
            campaign_name: { type: 'string', description: 'Campaign type to generate' }
          },
          required: ['lead_id', 'full_name', 'company']
        }
      },
      {
        name: 'send_outreach',
        description: 'Send personalized outreach email to a lead',
        inputSchema: {
          type: 'object',
          properties: {
            lead_id: { type: 'string', description: 'UUID of the lead' },
            email: { type: 'string', description: 'Email address to send to' },
            full_name: { type: 'string', description: 'Contact full name' }
          },
          required: ['lead_id', 'email']
        }
      },
      {
        name: 'process_booking',
        description: 'Detect interest in a reply and send Calendly booking link',
        inputSchema: {
          type: 'object',
          properties: {
            lead_id: { type: 'string', description: 'UUID of the lead' },
            full_name: { type: 'string', description: 'Contact full name' },
            company: { type: 'string', description: 'Company name' },
            reply_text: { type: 'string', description: 'The prospect reply to analyze' }
          },
          required: ['lead_id', 'full_name', 'reply_text']
        }
      },
      {
        name: 'get_pipeline_stats',
        description: 'Get complete pipeline health metrics and conversion rates',
        inputSchema: {
          type: 'object',
          properties: {},
          required: []
        }
      },
      {
        name: 'scan_city',
        description: 'Discover new businesses in a target city and industry via Google Maps',
        inputSchema: {
          type: 'object',
          properties: {
            city: { type: 'string', description: 'City to scan (e.g. Toronto)' },
            industry: { type: 'string', description: 'Industry to search (e.g. insurance broker)' },
            product_type: { type: 'string', description: 'Product category tag' }
          },
          required: ['city', 'industry']
        }
      },
      {
        name: 'get_lead',
        description: 'Get complete lead record from Supabase by ID or email',
        inputSchema: {
          type: 'object',
          properties: {
            lead_id: { type: 'string', description: 'UUID of the lead' },
            email: { type: 'string', description: 'Email address to look up' }
          },
          required: []
        }
      },
      {
        name: 'update_lead_status',
        description: 'Update a lead status in the pipeline',
        inputSchema: {
          type: 'object',
          properties: {
            lead_id: { type: 'string', description: 'UUID of the lead' },
            lead_status: { type: 'string', description: 'New status value' },
            notes: { type: 'string', description: 'Optional notes about the update' }
          },
          required: ['lead_id', 'lead_status']
        }
      },
      {
        name: 'list_leads',
        description: 'List leads filtered by status, industry, or both',
        inputSchema: {
          type: 'object',
          properties: {
            lead_status: { type: 'string', description: 'Filter by lead status' },
            industry: { type: 'string', description: 'Filter by industry' },
            limit: { type: 'number', description: 'Max results (default 20)' }
          },
          required: []
        }
      }
    ]
  }
};
